import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GameStep {
  START = 'START',
  STATE = 'STATE',
  SENSATIONS = 'SENSATIONS',
  TRIGGERS = 'TRIGGERS',
  ROLES = 'ROLES',
  FEAR = 'FEAR',
  EMOTION = 'EMOTION',
  REGULATION = 'REGULATION',
  INTEGRATION = 'INTEGRATION',
  END = 'END'
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface GameState {
  currentStep: GameStep;
  messages: Message[];
  isThinking: boolean;
}

import { GoogleGenAI, Chat } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";

class GeminiService {
  private ai: GoogleGenAI;
  private chat: Chat | null = null;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  public initChat() {
    this.chat = this.ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
      },
    });
  }

  public async sendMessage(message: string): Promise<string> {
    if (!this.chat) {
      this.initChat();
    }

    try {
      const result = await this.chat!.sendMessage({ message });
      return result.text || "I'm holding space for you, but I couldn't find the words just now. Could you please try sharing that again?";
    } catch (error) {
      console.error("Gemini API Error:", error);
      return "I apologize, my connection to the wisdom field was briefly interrupted. Let's take a deep breath and try that again.";
    }
  }
}

export const geminiService = new GeminiService();

import React from 'react';
import { GameStep } from '../types';
import { STEP_ORDER } from '../constants';

interface ProgressBarProps {
  currentStep: GameStep;
}

const ProgressBar: React.FC<ProgressBarProps> = ({ currentStep }) => {
  const currentIndex = STEP_ORDER.indexOf(currentStep);
  const totalSteps = STEP_ORDER.length - 1; // Exclude the end step
  const progress = Math.max(0, (currentIndex / totalSteps) * 100);

  return (
    <div className="w-full px-6 py-4 bg-white/50 backdrop-blur-sm sticky top-0 z-10 border-b border-purple-100">
      <div className="flex justify-between text-xs text-purple-400 font-medium mb-2 uppercase tracking-widest">
        <span>Awareness</span>
        <span>{currentIndex + 1} of {totalSteps + 1}</span>
        <span>Integration</span>
      </div>
      <div className="w-full bg-purple-100 rounded-full h-1.5 overflow-hidden">
        <div 
          className="bg-gradient-to-r from-purple-300 to-indigo-300 h-full transition-all duration-700 ease-in-out"
          style={{ width: `${progress}%` }}
        />
      </div>
    </div>
  );
};

export default ProgressBar;

import React from 'react';
import { Message } from '../types';

interface MessageBubbleProps {
  message: Message;
}

const MessageBubble: React.FC<MessageBubbleProps> = ({ message }) => {
  const isModel = message.role === 'model';

  return (
    <div className={`flex w-full mb-6 ${isModel ? 'justify-start' : 'justify-end'} message-fade-in`}>
      <div 
        className={`max-w-[85%] md:max-w-[70%] px-6 py-4 rounded-3xl shadow-sm leading-relaxed ${
          isModel 
            ? 'bg-white text-gray-700 border border-purple-50 rounded-tl-none' 
            : 'bg-indigo-500 text-white rounded-tr-none'
        }`}
      >
        <p className={`whitespace-pre-wrap text-lg ${isModel ? 'font-light italic' : 'font-normal'}`}>
          {message.text}
        </p>
        <div className={`text-[10px] mt-2 opacity-40 uppercase tracking-tighter ${isModel ? 'text-left' : 'text-right'}`}>
          {isModel ? 'LuminaSoul Guide' : 'You'} • {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </div>
