};

export default MessageBubble;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { geminiService } from './services/geminiService';
import { GameStep, Message, GameState } from './types';
import { STEP_ORDER, STEP_PROMPTS } from './constants';
import ProgressBar from './components/ProgressBar';
import MessageBubble from './components/MessageBubble';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    currentStep: GameStep.START,
    messages: [],
    isThinking: false,
  });
  const [inputValue, setInputValue] = useState('');
  const [hasStarted, setHasStarted] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [gameState.messages, gameState.isThinking]);

  const addMessage = (role: 'user' | 'model', text: string) => {
    const newMessage: Message = {
      id: Math.random().toString(36).substring(7),
      role,
      text,
      timestamp: new Date(),
    };
    setGameState(prev => ({
      ...prev,
      messages: [...prev.messages, newMessage]
    }));
  };

  const handleStart = async () => {
    setHasStarted(true);
    setGameState(prev => ({ ...prev, isThinking: true }));

    // Initialize session
    geminiService.initChat();

    // Start the game by sending the first prompt to the model (internally) or just displaying it.
    // We want the model to generate the welcome text to establish persona immediately.
    const initialPrompt = "I am ready to begin the LuminaSoul Nervous System Healing Game. Please start with the Welcome message and the question for Card Group A (Nervous System State).";
    const response = await geminiService.sendMessage(initialPrompt);

    addMessage('model', response);
    setGameState(prev => ({ ...prev, isThinking: false }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || gameState.isThinking) return;

    const userText = inputValue;
    setInputValue('');
    addMessage('user', userText);
    setGameState(prev => ({ ...prev, isThinking: true }));

    // Prepare prompt for model based on current progress
    const nextStepIndex = STEP_ORDER.indexOf(gameState.currentStep) + 1;
    const nextStep = STEP_ORDER[nextStepIndex] || GameStep.END;

    // Send the user input along with instruction to move to the next card group
    const response = await geminiService.sendMessage(userText);

    addMessage('model', response);
    setGameState(prev => ({ 
      ...prev, 
      currentStep: nextStep, 
      isThinking: false 
    }));
  };

  if (!hasStarted) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 serene-bg text-center">
        <div className="max-w-2xl w-full bg-white/40 backdrop-blur-lg p-12 rounded-[3rem] shadow-2xl border border-white/50">
          <h1 className="text-5xl md:text-6xl text-indigo-900 mb-6 font-serif">LuminaSoul</h1>
          <p className="text-xl text-indigo-700/80 mb-8 leading-relaxed font-light italic">
            "Your nervous system is a wise storyteller. Let's listen together."
          </p>
          <div className="space-y-4 text-gray-600 mb-12 text-left bg-white/50 p-6 rounded-2xl border border-purple-50">
            <div className="flex items-start space-x-3">
              <span className="text-purple-400 mt-1">✦</span>
              <p>A gentle, 8-step journey into nervous system regulation.</p>
            </div>
            <div className="flex items-start space-x-3">
              <span className="text-purple-400 mt-1">✦</span>
              <p>No diagnosis, no judgment, only compassionate reflection.</p>
            </div>
            <div className="flex items-start space-x-3">
              <span className="text-purple-400 mt-1">✦</span>
              <p>Moving at your pace to find inner wisdom and safety.</p>
            </div>
          </div>
          <button 
            onClick={handleStart}
            className="group relative px-10 py-4 bg-indigo-600 text-white rounded-full text-lg font-medium shadow-xl hover:bg-indigo-700 transition-all duration-300 transform hover:scale-105"
          >
            Begin Healing Journey
            <span className="absolute -top-1 -right-1 flex h-3 w-3">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-purple-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-3 w-3 bg-purple-500"></span>
            </span>
          </button>
          <p className="mt-8 text-xs text-gray-400 italic">
            Disclaimer: This is an AI coaching guide, not a substitute for clinical therapy or medical treatment.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-screen serene-bg overflow-hidden">
      <ProgressBar currentStep={gameState.currentStep} />

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto px-4 md:px-12 py-8 space-y-4"
      >
        <div className="max-w-4xl mx-auto">
          {gameState.messages.map((msg) => (
            <MessageBubble key={msg.id} message={msg} />
          ))}

          {gameState.isThinking && (
            <div className="flex justify-start mb-6 message-fade-in">
              <div className="bg-white/80 text-gray-400 px-6 py-4 rounded-3xl rounded-tl-none shadow-sm flex items-center space-x-2">
                <span className="italic text-sm font-light">LuminaSoul is reflecting</span>
                <div className="flex space-x-1">
                  <div className="w-1.5 h-1.5 bg-purple-300 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                  <div className="w-1.5 h-1.5 bg-purple-300 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                  <div className="w-1.5 h-1.5 bg-purple-300 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="p-4 md:p-8 bg-white/40 backdrop-blur-md border-t border-purple-100">
        <form onSubmit={handleSubmit} className="max-w-4xl mx-auto relative">
          <input
            type="text"
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
            placeholder={gameState.isThinking ? "Listening..." : "Share your heart here..."}
            disabled={gameState.isThinking || gameState.currentStep === GameStep.END}
            className="w-full px-8 py-5 pr-20 bg-white border border-purple-100 rounded-full shadow-lg focus:outline-none focus:ring-2 focus:ring-purple-300 transition-all text-lg placeholder:text-gray-300"
          />
          <button
            type="submit"
            disabled={!inputValue.trim() || gameState.isThinking || gameState.currentStep === GameStep.END}
            className="absolute right-2 top-2 bottom-2 px-6 bg-gradient-to-r from-indigo-500 to-purple-500 text-white rounded-full hover:shadow-md active:scale-95 disabled:opacity-30 transition-all"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
            </svg>
          </button>
        </form>
        <p className="mt-4 text-center text-xs text-gray-400 uppercase tracking-widest font-light">
          {gameState.currentStep === GameStep.END ? "This session has reached integration." : "Take your time. There is no rush."}
        </p>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { geminiService } from './services/geminiService';
import { GameStep, Message, GameState } from './types';
import { STEP_ORDER } from './constants';
import ProgressBar from './components/ProgressBar';
import MessageBubble from './components/MessageBubble';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>({
    currentStep: GameStep.START,
    messages: [],
    isThinking: false,
  });
  const [inputValue, setInputValue] = useState('');
  const [hasStarted, setHasStarted] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [gameState.messages, gameState.isThinking]);

  const addMessage = (role: 'user' | 'model', text: string) => {
    const newMessage: Message = {
      id: Math.random().toString(36).substring(7),
      role,
      text,
      timestamp: new Date(),
    };
    setGameState(prev => ({
      ...prev,
      messages: [...prev.messages, newMessage]
    }));
  };

  const handleStart = async () => {
    setHasStarted(true);
    setGameState(prev => ({ ...prev, isThinking: true }));

    geminiService.initChat();

    const initialPrompt = "I am ready to begin the LuminaSoul Nervous System Healing Game. Please start with the Welcome message and the question for Card Group A (Nervous System State).";
    const response = await geminiService.sendMessage(initialPrompt);

    addMessage('model', response);
    setGameState(prev => ({ ...prev, isThinking: false }));
  };

  const downloadSummary = () => {
    const summaryText = gameState.messages
      .map(m => `${m.role === 'model' ? 'LuminaSoul' : 'You'}: ${m.text}`)
      .join('\n\n');
    const blob = new Blob([summaryText], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `LuminaSoul_Summary_${new Date().toISOString().split('T')[0]}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || gameState.isThinking) return;

    const userText = inputValue;
    const lowText = userText.toLowerCase();
    const stopKeywords = ['stop', 'enough', 'i want to stop', "that's enough", 'end here', 'i am done'];
    const isStopRequested = stopKeywords.some(keyword => lowText.includes(keyword));

    setInputValue('');
    addMessage('user', userText);
    setGameState(prev => ({ ...prev, isThinking: true }));

    let prompt = userText;
    let nextStep = gameState.currentStep;

    if (isStopRequested) {
      prompt = `${userText} (SYSTEM NOTE: User has requested to stop. Please perform the LuminaSoul_Integration_Summary now and then conclude.)`;
      nextStep = GameStep.END;
    } else {
      const nextStepIndex = STEP_ORDER.indexOf(gameState.currentStep) + 1;
      nextStep = STEP_ORDER[nextStepIndex] || GameStep.END;
    }

    const response = await geminiService.sendMessage(prompt);

    addMessage('model', response);
    setGameState(prev => ({ 
      ...prev, 
      currentStep: nextStep, 
      isThinking: false 
    }));
  };

  if (!hasStarted) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 serene-bg text-center">
        <div className="max-w-2xl w-full bg-white/40 backdrop-blur-lg p-12 rounded-[3rem] shadow-2xl border border-white/50">
          <h1 className="text-5xl md:text-6xl text-indigo-900 mb-6 font-serif">LuminaSoul</h1>
          <p className="text-xl text-indigo-700/80 mb-8 leading-relaxed font-light italic">
            "Your nervous system is a wise storyteller. Let's listen together."
          </p>
          <div className="space-y-4 text-gray-600 mb-12 text-left bg-white/50 p-6 rounded-2xl border border-purple-50">
            <div className="flex items-start space-x-3">
              <span className="text-purple-400 mt-1">✦</span>
              <p>A gentle journey into nervous system regulation.</p>
            </div>
            <div className="flex items-start space-x-3">
              <span className="text-purple-400 mt-1">✦</span>
              <p>Compassionate reflection and spiritual grounding.</p>
            </div>
            <div className="flex items-start space-x-3">
              <span className="text-purple-400 mt-1">✦</span>
              <p>Moving at your pace to find inner wisdom and safety.</p>
            </div>
          </div>
          <button 
            onClick={handleStart}
            className="group relative px-10 py-4 bg-indigo-600 text-white rounded-full text-lg font-medium shadow-xl hover:bg-indigo-700 transition-all duration-300 transform hover:scale-105"
          >
            Begin Healing Journey
          </button>
        </div>
      </div>
    );
  }

  const isComplete = gameState.currentStep === GameStep.END;

  return (
    <div className="flex flex-col h-screen serene-bg overflow-hidden">
      <ProgressBar currentStep={gameState.currentStep} />

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto px-4 md:px-12 py-8 space-y-4"
      >
        <div className="max-w-4xl mx-auto pb-20">
          {gameState.messages.map((msg) => (
            <MessageBubble key={msg.id} message={msg} />
          ))}

          {gameState.isThinking && (
            <div className="flex justify-start mb-6 message-fade-in">
              <div className="bg-white/80 text-gray-400 px-6 py-4 rounded-3xl rounded-tl-none shadow-sm flex items-center space-x-2">
                <span className="italic text-sm font-light">LuminaSoul is reflecting</span>
                <div className="flex space-x-1">
                  <div className="w-1.5 h-1.5 bg-purple-300 rounded-full animate-bounce" style={{ animationDelay: '0s' }}></div>
                  <div className="w-1.5 h-1.5 bg-purple-300 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                  <div className="w-1.5 h-1.5 bg-purple-300 rounded-full animate-bounce" style={{ animationDelay: '0.4s' }}></div>
                </div>
              </div>
            </div>
          )}

          {isComplete && !gameState.isThinking && (
            <div className="mt-12 text-center message-fade-in">
              <div className="inline-block bg-white/60 backdrop-blur-sm p-8 rounded-[2rem] border border-purple-100 shadow-sm">
                <h3 className="text-2xl font-serif text-indigo-900 mb-2">Integration Complete</h3>
                <p className="text-indigo-600/60 mb-6 font-light italic">Your session is held in safe awareness.</p>
                <button 
                  onClick={downloadSummary}
                  className="px-6 py-2 bg-purple-100 text-purple-700 rounded-full text-sm font-medium hover:bg-purple-200 transition-colors"
                >
                  Download Integration Summary
                </button>
                <button 
                  onClick={() => window.location.reload()}
                  className="ml-4 px-6 py-2 border border-purple-200 text-purple-400 rounded-full text-sm font-medium hover:bg-white transition-colors"
                >
                  New Session
                </button>
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="p-4 md:p-8 bg-white/40 backdrop-blur-md border-t border-purple-100">
        {isComplete ? (
          <div className="max-w-4xl mx-auto text-center py-4">
            <p className="text-indigo-400 font-serif italic text-xl">"Awareness is the beginning of freedom."</p>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="max-w-4xl mx-auto relative">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              placeholder={gameState.isThinking ? "LuminaSoul is listening..." : "Share your heart..."}
              disabled={gameState.isThinking}
              className="w-full px-8 py-5 pr-20 bg-white border border-purple-100 rounded-full shadow-lg focus:outline-none focus:ring-2 focus:ring-purple-300 transition-all text-lg placeholder:text-gray-300"
            />
            <button
              type="submit"
              disabled={!inputValue.trim() || gameState.isThinking}
              className="absolute right-2 top-2 bottom-2 px-6 bg-gradient-to-r from-indigo-500 to-purple-500 text-white rounded-full hover:shadow-md active:scale-95 disabled:opacity-30 transition-all"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7l5 5m0 0l-5 5m5-5H6" />
              </svg>
            </button>
          </form>
        )}
        <div className="mt-4 flex justify-center space-x-4">
          <p className="text-[10px] text-gray-400 uppercase tracking-widest font-light">
            You can say "stop" at any time to finish your session early.
          </p>
        </div>
      </div>
    </div>
  );
};

export default App;

export enum GameStep {
  START = 'START',
  STATE = 'STATE',
  SENSATIONS = 'SENSATIONS',
  TRIGGERS = 'TRIGGERS',
  ROLES = 'ROLES',
  FEAR = 'FEAR',
  EMOTION = 'EMOTION',
  REGULATION = 'REGULATION',
  INTEGRATION = 'INTEGRATION',
  END = 'END'
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isQuestion?: boolean; // Helpful for editing history
}

export interface UserSession {
  id: string;
  messages: Message[];
  currentStep: GameStep;
  lastUpdated: Date;
  isComplete: boolean;
}

export interface User {
  email: string;
  sessions: UserSession[];
}

export type AppView = 'LANDING' | 'AUTH' | 'DASHBOARD' | 'CHAT' | 'REVIEW';

export interface GameState {
  currentStep: GameStep;
  messages: Message[];
  isThinking: boolean;
}

import React, { useState, useEffect, useRef } from 'react';
import { geminiService } from './services/geminiService';
import { GameStep, Message, User, UserSession, AppView } from './types';
import { STEP_ORDER } from './constants';
import ProgressBar from './components/ProgressBar';
import MessageBubble from './components/MessageBubble';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('LANDING');
  const [user, setUser] = useState<User | null>(null);
  const [activeSession, setActiveSession] = useState<UserSession | null>(null);
  const [isThinking, setIsThinking] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [editingMessageId, setEditingMessageId] = useState<string | null>(null);

  const scrollRef = useRef<HTMLDivElement>(null);

  // Persistence
  useEffect(() => {
    const savedUser = localStorage.getItem('lumina_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  useEffect(() => {
    if (user) {
      localStorage.setItem('lumina_user', JSON.stringify(user));
    }
  }, [user]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [activeSession?.messages, isThinking]);

  // Auth Handlers
  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    if (!authEmail || !authPassword) return;
    const existingUser = JSON.parse(localStorage.getItem(`user_${authEmail}`) || 'null');
    if (existingUser) {
      setUser(existingUser);
    } else {
      const newUser: User = { email: authEmail, sessions: [] };
      setUser(newUser);
      localStorage.setItem(`user_${authEmail}`, JSON.stringify(newUser));
    }
    setView('DASHBOARD');
  };

  const handleLogout = () => {
    setUser(null);
    setView('LANDING');
  };

  // Session Handlers
  const startNewSession = async () => {
    const newSession: UserSession = {
      id: Math.random().toString(36).substring(7),
      messages: [],
      currentStep: GameStep.START,
      lastUpdated: new Date(),
      isComplete: false,
    };
    setActiveSession(newSession);
    setView('CHAT');
    setIsThinking(true);

    geminiService.initChat();
    const response = await geminiService.sendMessage("I am ready to begin our session. Please provide a grounding welcome and ask the first question about my current nervous system state.");

    const modelMsg: Message = { id: 'm1', role: 'model', text: response, timestamp: new Date(), isQuestion: true };
    const updatedSession = { ...newSession, messages: [modelMsg] };
