          {activeSession.isComplete ? (
            <div className="max-w-4xl mx-auto text-center py-4">
              <p className="text-indigo-400 font-serif italic text-xl">"Awareness itself is healing."</p>
              <div className="mt-6 flex justify-center space-x-4">
                <button onClick={() => setView('DASHBOARD')} className="px-8 py-2 bg-indigo-500 text-white rounded-full font-medium shadow-md">Return Home</button>
                <button 
                  onClick={() => {
                    const summary = activeSession.messages.map(m => `${m.role === 'model' ? 'LuminaSoul' : 'You'}: ${m.text}`).join('\n\n');
                    const blob = new Blob([summary], { type: 'text/plain' });
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement('a');
                    a.href = url;
                    a.download = `LuminaSoul_Journey_${activeSession.id}.txt`;
                    a.click();
                  }}
                  className="px-8 py-2 bg-purple-100 text-purple-600 rounded-full font-medium"
                >
                  Save Summary
                </button>
              </div>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto">
              <form onSubmit={handleSubmit} className="relative">
                <input 
                  type="text" value={inputValue} onChange={e => setInputValue(e.target.value)}
                  placeholder={isThinking ? "Holding space..." : "Speak your truth..."}
                  disabled={isThinking}
                  className="w-full px-8 py-5 pr-20 bg-white border border-purple-100 rounded-full shadow-lg text-lg outline-none"
                />
                <button type="submit" disabled={!inputValue.trim() || isThinking} className="absolute right-2 top-2 bottom-2 px-6 bg-indigo-600 text-white rounded-full shadow-md">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7l5 5m0 0l-5 5m5-5H6" strokeWidth="2" strokeLinecap="round"/></svg>
                </button>
              </form>
              <div className="mt-3 flex justify-between items-center px-6">
                <button onClick={() => setView('REVIEW')} className="text-[10px] text-indigo-300 uppercase tracking-widest font-bold hover:text-indigo-500 transition-colors">Edit Previous Answers</button>
                <p className="text-[10px] text-gray-300 uppercase tracking-widest font-light">"Stop" at any time to summarize and end.</p>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  if (view === 'REVIEW' && activeSession) {
    return (
      <div className="min-h-screen serene-bg p-8">
        <div className="max-w-4xl mx-auto">
          <header className="flex justify-between items-center mb-12">
            <h1 className="text-4xl font-serif text-indigo-900">Your Journey Reflections</h1>
            <button onClick={() => setView('CHAT')} className="text-indigo-600 uppercase tracking-widest text-[10px] font-bold bg-white px-6 py-3 rounded-full shadow-sm hover:shadow-md transition-all">Back to Session</button>
          </header>

          <div className="space-y-8 pb-20">
            <div className="bg-purple-50/50 p-6 rounded-3xl text-sm text-indigo-400 italic font-light border border-purple-100/50">
              "Editing an earlier reflection will allow the session to flow forward from that new place of truth."
            </div>
            {activeSession.messages.filter(m => m.role === 'user').map((m, idx) => (
              <div key={m.id} className="bg-white/70 p-8 rounded-[2rem] shadow-sm border border-purple-100 message-fade-in relative group">
                <div className="flex justify-between items-start mb-4">
                  <h4 className="text-purple-400 uppercase tracking-widest text-[10px] font-bold">Reflection Point {idx + 1}</h4>
                  <button onClick={() => setEditingMessageId(m.id)} className="text-indigo-400 text-xs hover:underline opacity-0 group-hover:opacity-100 transition-opacity">Edit Reflection</button>
                </div>
                {editingMessageId === m.id ? (
                  <div className="space-y-4">
                    <textarea 
                      className="w-full p-6 border border-purple-200 rounded-3xl outline-none focus:ring-2 ring-purple-100 min-h-[120px] text-indigo-900 bg-white" 
                      defaultValue={m.text}
                      id={`edit-${m.id}`}
                    />
                    <div className="flex space-x-3">
                      <button 
                        onClick={() => handleEditAnswer(m.id, (document.getElementById(`edit-${m.id}`) as HTMLTextAreaElement).value)}
                        className="px-6 py-2 bg-indigo-500 text-white rounded-full text-xs font-medium shadow-sm"
                      >
                        Update My Truth
                      </button>
                      <button onClick={() => setEditingMessageId(null)} className="px-6 py-2 text-gray-400 text-xs font-medium bg-gray-50 rounded-full">Cancel</button>
                    </div>
                  </div>
                ) : (
                  <p className="text-xl text-indigo-900 italic font-light leading-relaxed">"{m.text}"</p>
                )}
              </div>
            ))}
            {activeSession.messages.filter(m => m.role === 'user').length === 0 && (
              <div className="text-center py-20 text-gray-400 italic">No reflections shared yet.</div>
            )}
          </div>
        </div>
      </div>
    );
  }

  return null;
};

export default App;

import React from 'react';
