              className="w-full px-8 py-4 rounded-full border border-purple-100 focus:ring-2 focus:ring-purple-200 outline-none transition-all"
            />
          </div>

          <button type="submit" className="w-full mt-8 py-4 bg-indigo-600 text-white rounded-full font-medium hover:bg-indigo-700 transition-all shadow-lg">
            {authMode === 'SIGNUP' ? 'Begin Journey' : 'Continue Journey'}
          </button>

          <div className="mt-6 text-center">
            <button 
