          </div>
        </div>
      </div>
    );
  }

  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { geminiService } from './services/geminiService';
import { GameStep, Message, User, UserSession, AppView } from './types';
import { STEP_ORDER } from './constants';
import ProgressBar from './components/ProgressBar';
import MessageBubble from './components/MessageBubble';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('LANDING');
  const [user, setUser] = useState<User | null>(null);
  const [activeSession, setActiveSession] = useState<UserSession | null>(null);
  const [isThinking, setIsThinking] = useState(false);
  const [inputValue, setInputValue] = useState('');

  // State to track which user message is currently being edited
  const [editingMessageId, setEditingMessageId] = useState<string | null>(null);

  // Auth States
  const [authMode, setAuthMode] = useState<'LOGIN' | 'SIGNUP'>('SIGNUP');
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: ''
  });
  const [verifyCode, setVerifyCode] = useState('');
  const [authError, setAuthError] = useState('');

  const scrollRef = useRef<HTMLDivElement>(null);

  // Persistence: Check for an active verified session on load
  useEffect(() => {
    const activeUserId = localStorage.getItem('lumina_active_user_id');
    if (activeUserId) {
      const savedUser = JSON.parse(localStorage.getItem(`user_${activeUserId}`) || 'null');
      if (savedUser && savedUser.isVerified) {
        setUser(savedUser);
        setView('DASHBOARD');
      }
    }
  }, []);

  // Sync user changes to localStorage
  useEffect(() => {
    if (user) {
      localStorage.setItem(`user_${user.email}`, JSON.stringify(user));
      if (user.isVerified) {
        localStorage.setItem('lumina_active_user_id', user.email);
      }
    }
  }, [user]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [activeSession?.messages, isThinking]);

  // Auth Handlers
  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');

    if (authMode === 'SIGNUP') {
      if (!formData.name || !formData.email || !formData.phone || !formData.password) {
        setAuthError('Please fill in your name, phone, email and password to begin.');
        return;
      }

      const existingUserStr = localStorage.getItem(`user_${formData.email}`);
      if (existingUserStr) {
        const existingUser = JSON.parse(existingUserStr);
        if (existingUser.isVerified) {
          setAuthError('An account with this email already exists. Please login.');
          return;
        }
      }

      const newUser: User = {
        name: formData.name,
        email: formData.email,
        phone: formData.phone,
        password: formData.password,
        isVerified: false,
        sessions: []
      };

      localStorage.setItem(`user_${formData.email}`, JSON.stringify(newUser));
      setUser(newUser);
      setView('VERIFY');
    } else {
      const savedUser = JSON.parse(localStorage.getItem(`user_${formData.email}`) || 'null');
      if (savedUser && savedUser.password === formData.password) {
        if (!savedUser.isVerified) {
          setUser(savedUser);
          setView('VERIFY');
        } else {
          setUser(savedUser);
          setView('DASHBOARD');
        }
      } else {
        setAuthError('Incorrect email or password. Please try again.');
      }
    }
  };

  const handleVerify = (e: React.FormEvent) => {
    e.preventDefault();
    if (verifyCode.length === 4) { 
      if (user) {
        const verifiedUser = { ...user, isVerified: true };
        setUser(verifiedUser);
        setView('DASHBOARD');
      }
    } else {
      setAuthError('Please enter a valid 4-digit verification code.');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('lumina_active_user_id');
    setUser(null);
    setFormData({ name: '', email: '', phone: '', password: '' });
    setView('LANDING');
  };

  // Session Handlers
  const startNewSession = async () => {
    const newSession: UserSession = {
      id: Math.random().toString(36).substring(7),
      messages: [],
      currentStep: GameStep.START,
      lastUpdated: new Date(),
      isComplete: false,
    };
    setActiveSession(newSession);
    setView('CHAT');
    setIsThinking(true);

    geminiService.initChat();
    // System instruction explicitly includes the ritual
    const response = await geminiService.sendMessage(`I am ${user?.name}. I am ready to begin my session. Please perform the LuminaSoul Grounding Breath ritual (3-2-7-1) and affirmation before asking the first reflective question.`);

    const modelMsg: Message = { id: 'm1', role: 'model', text: response, timestamp: new Date(), isQuestion: true };
    const updatedSession = { ...newSession, messages: [modelMsg] };
    setActiveSession(updatedSession);
    setIsThinking(false);
    updateUserSessions(updatedSession);
  };

  const resumeSession = (session: UserSession) => {
    setActiveSession(session);
    setView('CHAT');
    geminiService.initChat();
  };

  const updateUserSessions = (session: UserSession) => {
    if (!user) return;
    const otherSessions = user.sessions.filter(s => s.id !== session.id);
    const updatedUser = { ...user, sessions: [session, ...otherSessions] };
    setUser(updatedUser);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isThinking || !activeSession) return;

    const text = inputValue;
    setInputValue('');

    const userMsg: Message = { id: Date.now().toString(), role: 'user', text, timestamp: new Date() };
    const messagesWithUser = [...activeSession.messages, userMsg];
    setActiveSession(prev => prev ? { ...prev, messages: messagesWithUser } : null);
    setIsThinking(true);

    const lowText = text.toLowerCase();
    const distressKeywords = ['panic', 'overwhelmed', 'unsafe', 'help me', 'too much', 'cant breathe', 'scared'];
    const hasDistress = distressKeywords.some(k => lowText.includes(k));
    const isStopRequested = ['stop', 'enough', 'done', 'end'].some(k => lowText.includes(k));

    let prompt = text;
    let nextStep = activeSession.currentStep;

    if (hasDistress) {
      prompt = `${text} (SYSTEM: User expressed distress. Perform REGULATION INTERRUPTION grounding immediately.)`;
    } else if (isStopRequested) {
      prompt = `${text} (SYSTEM: User wants to stop. Perform the SESSION CLOSING FUNCTION.)`;
      nextStep = GameStep.END;
    } else {
      const idx = STEP_ORDER.indexOf(activeSession.currentStep) + 1;
      nextStep = STEP_ORDER[idx] || GameStep.END;
      // Remind AI to do the grounding breath before next question
      prompt = `${text} (SYSTEM: Acknowledge warmthly, then perform the mandatory LuminaSoul Grounding Breath ritual and affirmation before asking the next reflective question.)`;
    }

    const response = await geminiService.sendMessage(prompt);
    const modelMsg: Message = { id: (Date.now() + 1).toString(), role: 'model', text: response, timestamp: new Date(), isQuestion: true };

    const finalSession = { 
      ...activeSession, 
      messages: [...messagesWithUser, modelMsg],
      currentStep: nextStep,
      isComplete: nextStep === GameStep.END,
      lastUpdated: new Date()
    };
    setActiveSession(finalSession);
    setIsThinking(false);
    updateUserSessions(finalSession);
  };

  const handleEditAnswer = async (messageId: string, newText: string) => {
    if (!activeSession) return;
    const updatedMessages = activeSession.messages.map(m => m.id === messageId ? { ...m, text: newText } : m);

    setActiveSession(prev => prev ? { ...prev, messages: updatedMessages } : null);
    setEditingMessageId(null);
    setIsThinking(true);

    const response = await geminiService.sendMessage(`I have updated my previous answer to: "${newText}". (SYSTEM: Acknowledge warmly, perform Grounding Breath ritual, and continue flow.)`);
    const modelMsg: Message = { id: Date.now().toString(), role: 'model', text: response, timestamp: new Date() };

    const finalSession = { ...activeSession, messages: [...updatedMessages, modelMsg], lastUpdated: new Date() };
    setActiveSession(finalSession);
    setIsThinking(false);
    updateUserSessions(finalSession);
  };

  // Rendering Views
  if (view === 'LANDING') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 serene-bg text-center">
        <div className="max-w-2xl bg-white/40 backdrop-blur-lg p-12 rounded-[3rem] shadow-2xl border border-white/50">
          <h1 className="text-6xl text-indigo-900 mb-6 font-serif">LuminaSoul</h1>
          <p className="text-xl text-indigo-700/80 mb-12 font-light italic">"A sacred space for your nervous system to be heard."</p>
          <button onClick={() => setView('AUTH')} className="px-12 py-4 bg-indigo-600 text-white rounded-full text-lg shadow-xl hover:bg-indigo-700 transition-all font-medium">
            Enter the Space
          </button>
        </div>
      </div>
    );
  }

  if (view === 'AUTH') {
    return (
      <div className="min-h-screen flex items-center justify-center serene-bg p-6">
        <form onSubmit={handleAuth} className="bg-white p-10 rounded-[2rem] shadow-xl w-full max-w-md border border-purple-50">
          <h2 className="text-3xl font-serif text-indigo-900 mb-2 text-center">
            {authMode === 'SIGNUP' ? 'Join LuminaSoul' : 'Welcome Back'}
          </h2>
          <p className="text-gray-400 text-sm mb-8 text-center font-light">
            {authMode === 'SIGNUP' ? 'Create a space for your inner peace.' : 'Reconnect with your journey.'}
          </p>

          {authError && <div className="mb-6 p-4 bg-red-50 text-red-500 text-xs rounded-2xl border border-red-100">{authError}</div>}

          <div className="space-y-4">
            {authMode === 'SIGNUP' && (
              <>
                <input 
                  type="text" placeholder="Full Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})}
                  className="w-full px-6 py-4 rounded-full border border-purple-100 focus:ring-2 focus:ring-purple-200 outline-none transition-all"
                />
                <input 
                  type="tel" placeholder="Phone Number" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})}
                  className="w-full px-6 py-4 rounded-full border border-purple-100 focus:ring-2 focus:ring-purple-200 outline-none transition-all"
                />
              </>
            )}
            <input 
              type="email" placeholder="Email Address" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})}
              className="w-full px-6 py-4 rounded-full border border-purple-100 focus:ring-2 focus:ring-purple-200 outline-none transition-all"
            />
            <input 
              type="password" placeholder="Secure Password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})}
              className="w-full px-8 py-4 rounded-full border border-purple-100 focus:ring-2 focus:ring-purple-200 outline-none transition-all"
            />
          </div>

          <button type="submit" className="w-full mt-8 py-4 bg-indigo-600 text-white rounded-full font-medium hover:bg-indigo-700 transition-all shadow-lg">
            {authMode === 'SIGNUP' ? 'Begin Journey' : 'Continue Journey'}
          </button>

          <div className="mt-6 text-center">
            <button 
              type="button" 
              onClick={() => {
                setAuthMode(authMode === 'SIGNUP' ? 'LOGIN' : 'SIGNUP');
                setAuthError('');
              }}
              className="text-indigo-400 text-sm hover:underline"
            >
              {authMode === 'SIGNUP' ? 'Already have a space? Sign In' : "New here? Create your account"}
            </button>
          </div>
          <button type="button" onClick={() => setView('LANDING')} className="w-full mt-4 text-gray-300 text-xs hover:text-gray-500 transition-colors uppercase tracking-widest">Go Back</button>
        </form>
      </div>
    );
  }

  if (view === 'VERIFY') {
    return (
      <div className="min-h-screen flex items-center justify-center serene-bg p-6">
        <form onSubmit={handleVerify} className="bg-white p-10 rounded-[2rem] shadow-xl w-full max-w-md border border-purple-50 text-center">
          <div className="w-16 h-16 bg-indigo-50 rounded-full flex items-center justify-center mx-auto mb-6">
            <svg className="w-8 h-8 text-indigo-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h2 className="text-3xl font-serif text-indigo-900 mb-4">Confirm Your Email</h2>
          <p className="text-gray-500 font-light mb-8 leading-relaxed">
            We've sent a 4-digit verification code to your email inbox at <span className="font-medium text-indigo-600">{user?.email}</span>.
            <br/><span className="text-xs italic text-gray-400 mt-2 block">(Demo: Check your inbox for code 1111)</span>
          </p>

          {authError && <div className="mb-6 p-4 bg-red-50 text-red-500 text-xs rounded-2xl border border-red-100">{authError}</div>}

          <input 
            type="text" 
            placeholder="0000" 
            value={verifyCode} 
            maxLength={4}
            onChange={e => setVerifyCode(e.target.value.replace(/[^0-9]/g, ''))}
            className="w-full mb-8 px-6 py-4 text-center text-4xl tracking-[0.5em] font-serif border-b-2 border-indigo-100 focus:border-indigo-400 outline-none transition-all"
          />

          <button type="submit" className="w-full py-4 bg-indigo-600 text-white rounded-full font-medium hover:bg-indigo-700 transition-all shadow-lg">
            Verify & Continue
          </button>

          <button type="button" onClick={() => { setView('AUTH'); setAuthMode('SIGNUP'); }} className="mt-6 text-gray-400 text-sm hover:underline">Incorrect email? Go back</button>
        </form>
      </div>
    );
  }

  if (view === 'DASHBOARD' && user) {
    return (
      <div className="min-h-screen serene-bg p-8">
        <div className="max-w-4xl mx-auto">
          <header className="flex justify-between items-end mb-12">
            <div>
              <p className="text-indigo-400 text-xs uppercase tracking-widest font-bold mb-1">Peace be with you</p>
              <h1 className="text-5xl font-serif text-indigo-900">{user.name}</h1>
            </div>
            <button onClick={handleLogout} className="text-indigo-300 hover:text-indigo-600 uppercase tracking-widest text-[10px] font-bold border border-indigo-50 px-4 py-2 rounded-full">Sign Out</button>
          </header>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <button onClick={startNewSession} className="bg-white p-10 rounded-[3rem] shadow-sm border border-purple-50 text-left hover:shadow-xl transition-all group relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/50 rounded-bl-full -mr-10 -mt-10 transition-transform group-hover:scale-110"></div>
              <div className="w-12 h-12 bg-indigo-600 text-white rounded-2xl flex items-center justify-center mb-6 shadow-lg shadow-indigo-100">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="2" strokeLinecap="round"/></svg>
              </div>
              <h3 className="text-3xl font-serif text-indigo-900 mb-2">New Journey</h3>
              <p className="text-gray-500 font-light leading-relaxed">Let's find clarity and calm together in a fresh reflection.</p>
            </button>

            <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-purple-50 flex flex-col h-full">
              <h3 className="text-2xl font-serif text-indigo-900 mb-6 flex items-center">
                <svg className="w-5 h-5 mr-3 text-purple-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="2" strokeLinecap="round"/></svg>
                Previous Sessions
              </h3>
              <div className="space-y-4 flex-1 overflow-y-auto pr-2 custom-scrollbar">
                {user.sessions.length > 0 ? (
                  user.sessions.map(s => (
                    <div key={s.id} className="p-5 border border-purple-50 rounded-3xl hover:bg-purple-50 transition-all cursor-pointer group" onClick={() => resumeSession(s)}>
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-sm font-semibold text-indigo-800">Journey {s.id.slice(0,4).toUpperCase()}</span>
                        <span className="text-[10px] text-gray-400 uppercase tracking-tighter">{new Date(s.lastUpdated).toLocaleDateString()}</span>
                      </div>
                      <p className="text-xs text-gray-400 italic line-clamp-1 group-hover:text-indigo-400">"{s.messages[s.messages.length-1]?.text.slice(0, 100)}..."</p>
                    </div>
                  ))
                ) : (
                  <div className="flex flex-col items-center justify-center h-full text-center py-8">
                    <p className="text-sm text-gray-300 italic">No journeys recorded yet.</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'CHAT' && activeSession) {
    return (
      <div className="flex flex-col h-screen serene-bg overflow-hidden">
        <div className="px-6 py-4 bg-white/80 border-b border-purple-50 flex justify-between items-center">
          <button onClick={() => setView('DASHBOARD')} className="text-indigo-400 text-sm flex items-center">
            <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="2" strokeLinecap="round"/></svg>
            Home
          </button>
          <div className="text-center">
            <h2 className="text-xl font-serif text-indigo-900">Healing Space</h2>
            <div className="text-[9px] uppercase tracking-widest text-purple-300 font-bold">Session Active</div>
          </div>
          <button onClick={() => setView('REVIEW')} className="text-indigo-400 text-sm">Review</button>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto px-4 md:px-12 py-8 space-y-4">
          <div className="max-w-4xl mx-auto">
            {activeSession.messages.map((msg) => (
              <MessageBubble key={msg.id} message={msg} />
            ))}
            {isThinking && (
              <div className="flex justify-start mb-6 message-fade-in">
                <div className="bg-white/80 text-gray-400 px-6 py-4 rounded-3xl rounded-tl-none shadow-sm italic text-sm font-light">
                  LuminaSoul is reflecting...
                </div>
              </div>
            )}
          </div>
        </div>

        <div className="p-4 md:p-8 bg-white/60 backdrop-blur-md border-t border-purple-100">
          {activeSession.isComplete ? (
            <div className="max-w-4xl mx-auto text-center py-4">
              <p className="text-indigo-400 font-serif italic text-xl">"Awareness itself is healing."</p>
              <div className="mt-6 flex justify-center space-x-4">
                <button onClick={() => setView('DASHBOARD')} className="px-8 py-2 bg-indigo-500 text-white rounded-full font-medium shadow-md">Dashboard</button>
              </div>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto">
              <form onSubmit={handleSubmit} className="relative">
                <input 
                  type="text" value={inputValue} onChange={e => setInputValue(e.target.value)}
                  placeholder={isThinking ? "Holding space..." : "Share what's in your heart..."}
                  disabled={isThinking}
                  className="w-full px-8 py-5 pr-20 bg-white border border-purple-100 rounded-full shadow-lg text-lg outline-none"
                />
                <button type="submit" disabled={!inputValue.trim() || isThinking} className="absolute right-2 top-2 bottom-2 px-6 bg-indigo-600 text-white rounded-full shadow-md">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7l5 5m0 0l-5 5m5-5H6" strokeWidth="2" strokeLinecap="round"/></svg>
                </button>
              </form>
            </div>
          )}
        </div>
      </div>
    );
  }

  if (view === 'REVIEW' && activeSession) {
    return (
      <div className="min-h-screen serene-bg p-8">
        <div className="max-w-4xl mx-auto">
          <header className="flex justify-between items-center mb-12">
            <h1 className="text-4xl font-serif text-indigo-900">Journey Reflections</h1>
            <button onClick={() => setView('CHAT')} className="text-indigo-600 uppercase tracking-widest text-[10px] font-bold bg-white px-6 py-3 rounded-full shadow-sm">Back to Space</button>
          </header>
          <div className="space-y-8 pb-20">
            {activeSession.messages.filter(m => m.role === 'user').map((m, idx) => (
              <div key={m.id} className="bg-white/70 p-8 rounded-[2rem] shadow-sm border border-purple-100 relative group">
                <div className="flex justify-between items-start mb-4">
                  <h4 className="text-purple-400 uppercase tracking-widest text-[10px] font-bold">Reflection {idx + 1}</h4>
                  <button onClick={() => setEditingMessageId(m.id)} className="text-indigo-400 text-xs hover:underline opacity-0 group-hover:opacity-100 transition-opacity">Edit</button>
                </div>
                {editingMessageId === m.id ? (
                  <div className="space-y-4">
                    <textarea 
                      className="w-full p-6 border border-purple-200 rounded-3xl outline-none min-h-[120px]" 
                      defaultValue={m.text}
                      id={`edit-${m.id}`}
                    />
                    <button 
                      onClick={() => handleEditAnswer(m.id, (document.getElementById(`edit-${m.id}`) as HTMLTextAreaElement).value)}
                      className="px-6 py-2 bg-indigo-500 text-white rounded-full text-xs"
                    >
                      Update Truth
                    </button>
                    <button onClick={() => setEditingMessageId(null)} className="px-6 py-2 text-gray-400 text-xs">Cancel</button>
                  </div>
                ) : (
                  <p className="text-xl text-indigo-900 italic font-light">"{m.text}"</p>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  return null;
};

export default App;

