import React, { useState, useEffect, useRef } from 'react';
import { geminiService } from './services/geminiService';
import { GameStep, Message, User, UserSession, AppView } from './types';
import { STEP_ORDER } from './constants';
import ProgressBar from './components/ProgressBar';
import MessageBubble from './components/MessageBubble';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('LANDING');
  const [user, setUser] = useState<User | null>(null);
  const [activeSession, setActiveSession] = useState<UserSession | null>(null);
  const [isThinking, setIsThinking] = useState(false);
  const [inputValue, setInputValue] = useState('');

  // State to track which user message is currently being edited
  const [editingMessageId, setEditingMessageId] = useState<string | null>(null);

  // Auth States
  const [authMode, setAuthMode] = useState<'LOGIN' | 'SIGNUP'>('SIGNUP');
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: ''
  });
  const [verifyCode, setVerifyCode] = useState('');
  const [authError, setAuthError] = useState('');

  const scrollRef = useRef<HTMLDivElement>(null);

  // Persistence: Check for an active verified session on load
  useEffect(() => {
    const activeUserId = localStorage.getItem('lumina_active_user_id');
    if (activeUserId) {
      const savedUser = JSON.parse(localStorage.getItem(`user_${activeUserId}`) || 'null');
      if (savedUser && savedUser.isVerified) {
        setUser(savedUser);
        setView('DASHBOARD');
      }
    }
  }, []);

  // Sync user changes to localStorage
  useEffect(() => {
    if (user) {
      localStorage.setItem(`user_${user.email}`, JSON.stringify(user));
      if (user.isVerified) {
        localStorage.setItem('lumina_active_user_id', user.email);
      }
    }
  }, [user]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [activeSession?.messages, isThinking]);

  // Auth Handlers
  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');

    if (authMode === 'SIGNUP') {
      if (!formData.name || !formData.email || !formData.phone || !formData.password) {
        setAuthError('Please fill in your name, phone, email and password to begin.');
        return;
      }

      const existingUserStr = localStorage.getItem(`user_${formData.email}`);
      if (existingUserStr) {
        const existingUser = JSON.parse(existingUserStr);
        if (existingUser.isVerified) {
          setAuthError('An account with this email already exists. Please login.');
          return;
        }
      }

      const newUser: User = {
        name: formData.name,
        email: formData.email,
        phone: formData.phone,
        password: formData.password,
        isVerified: false,
        sessions: []
      };

      localStorage.setItem(`user_${formData.email}`, JSON.stringify(newUser));
      setUser(newUser);
      setView('VERIFY');
    } else {
      const savedUser = JSON.parse(localStorage.getItem(`user_${formData.email}`) || 'null');
      if (savedUser && savedUser.password === formData.password) {
        if (!savedUser.isVerified) {
          setUser(savedUser);
          setView('VERIFY');
        } else {
          setUser(savedUser);
          setView('DASHBOARD');
        }
      } else {
        setAuthError('Incorrect email or password. Please try again.');
      }
    }
  };

  const handleVerify = (e: React.FormEvent) => {
    e.preventDefault();
    if (verifyCode.length === 4) { 
      if (user) {
        const verifiedUser = { ...user, isVerified: true };
        setUser(verifiedUser);
        setView('DASHBOARD');
      }
    } else {
      setAuthError('Please enter a valid 4-digit verification code.');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('lumina_active_user_id');
    setUser(null);
    setFormData({ name: '', email: '', phone: '', password: '' });
    setView('LANDING');
