    const response = await geminiService.sendMessage(`I have updated my previous answer to: "${newText}". (SYSTEM: Acknowledge warmly, perform the mandatory LuminaSoul Grounding Breath ritual, and continue flow.)`);
    const modelMsg: Message = { id: Date.now().toString(), role: 'model', text: response, timestamp: new Date() };

    const finalSession = { ...activeSession, messages: [...updatedMessages, modelMsg], lastUpdated: new Date() };
    setActiveSession(finalSession);
    setIsThinking(false);
    updateUserSessions(finalSession);
  };

  // Rendering Views
  if (view === 'LANDING') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 serene-bg text-center">
        <div className="max-w-2xl bg-white/40 backdrop-blur-lg p-12 rounded-[3rem] shadow-2xl border border-white/50">
          <h1 className="text-6xl text-indigo-900 mb-6 font-serif">LuminaSoul</h1>
