          <button type="button" onClick={() => { setView('AUTH'); setAuthMode('SIGNUP'); }} className="mt-6 text-gray-400 text-sm hover:underline">Incorrect email? Go back</button>
        </form>
      </div>
    );
  }

  if (view === 'DASHBOARD' && user) {
    return (
      <div className="min-h-screen serene-bg p-8">
        <div className="max-w-4xl mx-auto">
          <header className="flex justify-between items-end mb-12">
            <div>
