          </header>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <button onClick={startNewSession} className="bg-white p-10 rounded-[3rem] shadow-sm border border-purple-50 text-left hover:shadow-xl transition-all group relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/50 rounded-bl-full -mr-10 -mt-10 transition-transform group-hover:scale-110"></div>
              <div className="w-12 h-12 bg-indigo-600 text-white rounded-2xl flex items-center justify-center mb-6 shadow-lg shadow-indigo-100">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="2" strokeLinecap="round"/></svg>
              </div>
              <h3 className="text-3xl font-serif text-indigo-900 mb-2">New Journey</h3>
              <p className="text-gray-500 font-light leading-relaxed">Let's find clarity and calm together in a fresh reflection.</p>
            </button>

            <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-purple-50 flex flex-col h-full">
              <h3 className="text-2xl font-serif text-indigo-900 mb-6 flex items-center">
                <svg className="w-5 h-5 mr-3 text-purple-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="2" strokeLinecap="round"/></svg>
                Previous Sessions
              </h3>
              <div className="space-y-4 flex-1 overflow-y-auto pr-2 custom-scrollbar">
                {user.sessions.length > 0 ? (
                  user.sessions.map(s => (
                    <div key={s.id} className="p-5 border border-purple-50 rounded-3xl hover:bg-purple-50 transition-all cursor-pointer group" onClick={() => resumeSession(s)}>
                      <div className="flex justify-between items-center mb-2">
                        <span className="text-sm font-semibold text-indigo-800">Journey {s.id.slice(0,4).toUpperCase()}</span>
                        <span className="text-[10px] text-gray-400 uppercase tracking-tighter">{new Date(s.lastUpdated).toLocaleDateString()}</span>
                      </div>
                      <p className="text-xs text-gray-400 italic line-clamp-1 group-hover:text-indigo-400">"{s.messages[s.messages.length-1]?.text.slice(0, 100)}..."</p>
                    </div>
                  ))
                ) : (
                  <div className="flex flex-col items-center justify-center h-full text-center py-8">
                    <p className="text-sm text-gray-300 italic">No journeys recorded yet.</p>
                  </div>
