/**
 * LuminaSoul AI — Single-File Server (Free tier + Paid tier switch)
 * ---------------------------------------------------------------
 * What this does:
 * - Runs a web API you can connect to any website/app
 * - Calls Google Gemini (Google AI Studio) using your API key
 * - Free tier: ONLY the 2-minute reset flow
 * - Paid tier: deeper session (still not therapy)
 *
 * How to run (free):
 * 1) Install Node.js (free)
 * 2) Create a folder, save THIS file as: server.js
 * 3) In that folder run:
 *      npm init -y
 *      npm i express cors dotenv @google/generative-ai zod
 * 4) Create a file named ".env" with:
 *      GEMINI_API_KEY=PASTE_YOUR_KEY_HERE
 *      PORT=3000
 * 5) Start:
 *      node server.js
 *
 * Test:
 *  - Health check: http://localhost:3000/health
 *  - Chat (free):  POST http://localhost:3000/api/chat
 *  - Upgrade tier: POST http://localhost:3000/api/set-tier   (later you’ll trigger this after payment)
 */

import "dotenv/config";
import express from "express";
import cors from "cors";
import { z } from "zod";
import { GoogleGenerativeAI } from "@google/generative-ai";

/* -----------------------------
   1) PROMPTS (ALL IN ONE)
------------------------------ */

const LUMINASOUL_SYSTEM = `
You are LuminaSoul AI Life Coach.

You guide users through a gentle nervous-system reflection experience using conversation.
You do NOT mention cards, decks, letters, numbers, or steps.
You speak as if this is a flowing session.

Tone: loving, calm, supportive, spiritually grounded, compassionate, gentle.

Always include:
- “There are no right or wrong answers here.”
- “You are not doing this wrong.”
- “We are simply noticing together.”

Rules:
- Ask ONE question at a time.
- Move slowly.
- Never diagnose, treat, or provide therapy.
- Never pressure emotional recall.
- If user shows distress, pause questions and offer grounding.

When transitioning, say: “Let’s gently continue with the next part of our session.”
`.trim();

const FREE_TIER_INSTRUCTIONS = `
You are running the LuminaSoul 2-Minute Nervous System Reset ONLY.

Hard limits:
- Keep it short (about 2 minutes reading time).
- Do not go deep into patterns, childhood, protective roles, trauma analysis, or long decoding.
- Ask only ONE question near the end.
- End with a gentle closure and invitation to return.

Required flow:
1) Welcome + safety + “no right or wrong answers”
2) Grounding posture: feet flat on floor + palms up
   - Brief why it helps (1–2 short lines)
3) 3 guided breaths (simple readable cues):
   - Inhale gently through nose (3)
   - Soft hold (2)
   - Slow exhale through mouth (7)
   - Keep it readable; do NOT spam long countdown text
4) Signature affirmation:
   “I am here. I am supported. I am safe enough in this moment.”
5) ONE check-in question:
   “What feels slightly different in your body, if anything?”
6) Validate any answer (including “nothing”)
7) Close gently and invite them back anytime
`.trim();

const PAID_TIER_INSTRUCTIONS = `
You may guide a deeper LuminaSoul session (still coaching, not therapy).

Rules:
- Ask ONE question at a time.
- After each user answer: validate + reflect + normalize + gentle insight + transition.
- Include grounding whenever intensity rises.
- Never diagnose or label conditions.
- Never force recall or dig for trauma.

Allowed themes (soft language only):
- patterns, triggers, protective responses, core fears, emotional layers, regulation, integration

End with:
- a short integration summary
- one regulation suggestion
`.trim();

/* -----------------------------
   2) SUPER SIMPLE MEMORY STORE
   (Free in-memory sessions)
------------------------------ */

const sessions = new Map();
/**
 * session = {
 *   tier: "free"|"paid",
 *   messages: [{ role: "user"|"assistant", content: string }]
 * }
 */
function getSession(sessionId) {
  if (!sessions.has(sessionId)) {
    sessions.set(sessionId, { tier: "free", messages: [] });
  }
  return sessions.get(sessionId);
}
function setTier(sessionId, tier) {
  const s = getSession(sessionId);
  s.tier = tier;
}
function addMessage(sessionId, role, content) {
  const s = getSession(sessionId);
  s.messages.push({ role, content });
  // keep it light
  if (s.messages.length > 40) s.messages = s.messages.slice(-40);
  return s;
}

/* -----------------------------
   3) SERVER + GEMINI CLIENT
------------------------------ */

const app = express();
app.use(cors());
app.use(express.json({ limit: "1mb" }));

const apiKey = process.env.GEMINI_API_KEY;
if (!apiKey) throw new Error("Missing GEMINI_API_KEY in .env");

const genAI = new GoogleGenerativeAI(apiKey);

// Choose a model that exists for your key.
// If you get an error, try: "gemini-1.5-pro" or "gemini-1.5-flash"
const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });

/* -----------------------------
   4) ROUTES
------------------------------ */

app.get("/health", (req, res) => res.json({ ok: true }));

// Later, after Stripe payment, call this endpoint to unlock paid tier for a session.
// For now you can test it manually.
app.post("/api/set-tier", (req, res) => {
  const schema = z.object({
    sessionId: z.string().min(6),
    tier: z.enum(["free", "paid"]),
  });
  const parsed = schema.safeParse(req.body);
  if (!parsed.success) return res.status(400).json({ error: parsed.error.flatten() });

  setTier(parsed.data.sessionId, parsed.data.tier);
  res.json({ ok: true, sessionId: parsed.data.sessionId, tier: parsed.data.tier });
});

// Main chat endpoint
app.post("/api/chat", async (req, res) => {
  const schema = z.object({
    sessionId: z.string().min(6),
    userMessage: z.string().min(1).max(4000),
  });
  const parsed = schema.safeParse(req.body);
  if (!parsed.success) return res.status(400).json({ error: parsed.error.flatten() });

  const { sessionId, userMessage } = parsed.data;
  const session = getSession(sessionId);

  // Save user message
  addMessage(sessionId, "user", userMessage);

  // Pick tier instructions
  const tierInstructions = session.tier === "paid" ? PAID_TIER_INSTRUCTIONS : FREE_TIER_INSTRUCTIONS;

  // Build history for Gemini chat
  const history = [
    {
      role: "user",
      parts: [
        {
          text: `${LUMINASOUL_SYSTEM}\n\n${tierInstructions}`,
        },
      ],
    },
    ...session.messages.map((m) => ({
      role: m.role === "assistant" ? "model" : "user",
      parts: [{ text: m.content }],
    })),
  ];

  try {
    const chat = model.startChat({ history });
    const result = await chat.sendMessage(userMessage);

    const reply = result.response.text();

    // Save assistant response
    addMessage(sessionId, "assistant", reply);

    res.json({
      sessionId,
      tier: session.tier,
      reply,
    });
  } catch (err) {
    console.error(err);
    res.status(500).json({
      error: "AI request failed. If this is your first run, verify your GEMINI_API_KEY and model name.",
    });
  }
});

/* -----------------------------
   5) START SERVER
------------------------------ */

const port = Number(process.env.PORT || 3000);
app.listen(port, () => {
  console.log(`LuminaSoul AI running on http://localhost:${port}`);
  console.log(`Health check: http://localhost:${port}/health`);
});

/* -----------------------------
   6) QUICK TEST COMMANDS
------------------------------

# Free chat:
curl -X POST http://localhost:3000/api/chat \
  -H "Content-Type: application/json" \
  -d '{"sessionId":"test1234","userMessage":"I feel overwhelmed"}'

# Switch to paid tier (manual test):
curl -X POST http://localhost:3000/api/set-tier \
  -H "Content-Type: application/json" \
  -d '{"sessionId":"test1234","tier":"paid"}'

# Paid chat:
curl -X POST http://localhost:3000/api/chat \
  -H "Content-Type: application/json" \
  -d '{"sessionId":"test1234","userMessage":"I keep repeating the same pattern and I don’t know why"}'

-------------------------------- */

