export enum GameStep {
  START = 'START',
  STATE = 'STATE',
  SENSATIONS = 'SENSATIONS',
  TRIGGERS = 'TRIGGERS',
  ROLES = 'ROLES',
  FEAR = 'FEAR',
  EMOTION = 'EMOTION',
  REGULATION = 'REGULATION',
  INTEGRATION = 'INTEGRATION',
  END = 'END'
}

export type SessionTier = 'free' | 'paid';

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
  isQuestion?: boolean;
}

export interface UserSession {
  id: string;
  messages: Message[];
  currentStep: GameStep;
  lastUpdated: Date;
  isComplete: boolean;
  tier: SessionTier;
}

export interface User {
  name: string;
  email: string;
  phone: string;
  password?: string;
  isVerified: boolean;
  sessions: UserSession[];
}

export type AppView = 'LANDING' | 'AUTH' | 'VERIFY' | 'DASHBOARD' | 'CHAT' | 'REVIEW';

export interface GameState {
  currentStep: GameStep;
  messages: Message[];
  isThinking: boolean;
}

import React, { useState, useEffect, useRef } from 'react';
import { geminiService } from './services/geminiService';
import { GameStep, Message, User, UserSession, AppView, SessionTier } from './types';
import { STEP_ORDER } from './constants';
import ProgressBar from './components/ProgressBar';
import MessageBubble from './components/MessageBubble';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('LANDING');
  const [user, setUser] = useState<User | null>(null);
  const [activeSession, setActiveSession] = useState<UserSession | null>(null);
  const [isThinking, setIsThinking] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingMessageId, setEditingMessageId] = useState<string | null>(null);

  // Auth States
  const [authMode, setAuthMode] = useState<'LOGIN' | 'SIGNUP'>('SIGNUP');
  const [formData, setFormData] = useState({ name: '', email: '', phone: '', password: '' });
  const [verifyCode, setVerifyCode] = useState('');
  const [authError, setAuthError] = useState('');

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const activeUserId = localStorage.getItem('lumina_active_user_id');
    if (activeUserId) {
      const savedUser = JSON.parse(localStorage.getItem(`user_${activeUserId}`) || 'null');
      if (savedUser && savedUser.isVerified) {
        setUser(savedUser);
        setView('DASHBOARD');
      }
    }
  }, []);

  useEffect(() => {
    if (user) {
      localStorage.setItem(`user_${user.email}`, JSON.stringify(user));
      if (user.isVerified) localStorage.setItem('lumina_active_user_id', user.email);
    }
  }, [user]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [activeSession?.messages, isThinking]);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    if (authMode === 'SIGNUP') {
      if (!formData.name || !formData.email || !formData.phone || !formData.password) {
        setAuthError('Please fill in all fields.');
        return;
      }
      localStorage.setItem(`user_${formData.email}`, JSON.stringify({ ...formData, isVerified: false, sessions: [] }));
      setUser({ ...formData, isVerified: false, sessions: [] });
      setView('VERIFY');
    } else {
      const savedUser = JSON.parse(localStorage.getItem(`user_${formData.email}`) || 'null');
      if (savedUser && savedUser.password === formData.password) {
        setUser(savedUser);
        setView(savedUser.isVerified ? 'DASHBOARD' : 'VERIFY');
      } else {
        setAuthError('Incorrect details. Please try again.');
      }
    }
  };

  const handleVerify = (e: React.FormEvent) => {
    e.preventDefault();
    if (verifyCode === '1111') {
      if (user) {
        const verifiedUser = { ...user, isVerified: true };
        setUser(verifiedUser);
        setView('DASHBOARD');
      }
    } else {
      setAuthError('Code is 1111 for this demo.');
    }
  };

  const startNewSession = async (tier: SessionTier) => {
    const newSession: UserSession = {
      id: Math.random().toString(36).substring(7),
      messages: [],
      currentStep: GameStep.START,
      lastUpdated: new Date(),
      isComplete: false,
      tier
    };
    setActiveSession(newSession);
    setView('CHAT');
    setIsThinking(true);
    geminiService.initChat();

    const tierContext = tier === 'free' 
      ? "I am starting a 2-MINUTE NERVOUS SYSTEM RESET. Keep it very brief." 
      : "I am starting a DEEP JOURNEY. We will move through multiple layers of awareness.";

    const response = await geminiService.sendMessage(
      `I am ${user?.name}. ${tierContext} (SYSTEM: Acknowledge warmly, perform the mandatory LuminaSoul Grounding Breath ritual (3-2-7-1 Technique) and affirmation, then ask the first question.)`
    );

    const modelMsg: Message = { id: 'm1', role: 'model', text: response, timestamp: new Date(), isQuestion: true };
    const updatedSession = { ...newSession, messages: [modelMsg] };
    setActiveSession(updatedSession);
    setIsThinking(false);
    updateUserSessions(updatedSession);
  };

  const updateUserSessions = (session: UserSession) => {
    if (!user) return;
    const otherSessions = user.sessions.filter(s => s.id !== session.id);
    setUser({ ...user, sessions: [session, ...otherSessions] });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isThinking || !activeSession) return;

    const text = inputValue;
    setInputValue('');
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text, timestamp: new Date() };
    const messagesWithUser = [...activeSession.messages, userMsg];
    setActiveSession({ ...activeSession, messages: messagesWithUser });
    setIsThinking(true);

    let nextStep = activeSession.currentStep;
    const idx = STEP_ORDER.indexOf(activeSession.currentStep) + 1;
    nextStep = STEP_ORDER[idx] || GameStep.END;

    // For Free tier, force end after 2-3 exchanges
    if (activeSession.tier === 'free' && activeSession.messages.length >= 3) {
      nextStep = GameStep.END;
    }

    const prompt = `${text} (SYSTEM: Acknowledge warmly. Then, before asking the next question, perform the mandatory LuminaSoul Grounding Breath ritual (3-2-7-1) and the affirmation "My body is listening. I am allowed to slow down.")`;

    const response = await geminiService.sendMessage(prompt);
    const modelMsg: Message = { id: (Date.now() + 1).toString(), role: 'model', text: response, timestamp: new Date(), isQuestion: true };

    const finalSession = { 
      ...activeSession, 
      messages: [...messagesWithUser, modelMsg],
      currentStep: nextStep,
      isComplete: nextStep === GameStep.END,
      lastUpdated: new Date()
    };
    setActiveSession(finalSession);
    setIsThinking(false);
    updateUserSessions(finalSession);
  };

  if (view === 'LANDING') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 serene-bg text-center">
        <div className="max-w-2xl bg-white/40 backdrop-blur-lg p-12 rounded-[3rem] shadow-2xl border border-white/50">
          <h1 className="text-6xl text-indigo-900 mb-6 font-serif">LuminaSoul</h1>
          <p className="text-xl text-indigo-700/80 mb-12 font-light italic">"A sacred space for your nervous system to be heard."</p>
          <button onClick={() => setView('AUTH')} className="px-12 py-4 bg-indigo-600 text-white rounded-full text-lg shadow-xl hover:bg-indigo-700 transition-all font-medium">
            Enter the Space
          </button>
        </div>
      </div>
    );
  }

  if (view === 'AUTH') {
    return (
      <div className="min-h-screen flex items-center justify-center serene-bg p-6">
        <form onSubmit={handleAuth} className="bg-white p-10 rounded-[2rem] shadow-xl w-full max-w-md border border-purple-50">
          <h2 className="text-3xl font-serif text-indigo-900 mb-2 text-center">{authMode === 'SIGNUP' ? 'Join LuminaSoul' : 'Welcome Back'}</h2>
          <p className="text-gray-400 text-sm mb-8 text-center font-light">{authMode === 'SIGNUP' ? 'Create a space for your inner peace.' : 'Reconnect with your journey.'}</p>
          {authError && <div className="mb-6 p-4 bg-red-50 text-red-500 text-xs rounded-2xl border border-red-100">{authError}</div>}
          <div className="space-y-4">
            {authMode === 'SIGNUP' && (
              <>
                <input type="text" placeholder="Full Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-6 py-4 rounded-full border border-purple-100 outline-none" />
                <input type="tel" placeholder="Phone Number" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full px-6 py-4 rounded-full border border-purple-100 outline-none" />
              </>
            )}
            <input type="email" placeholder="Email Address" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full px-6 py-4 rounded-full border border-purple-100 outline-none" />
            <input type="password" placeholder="Password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full px-8 py-4 rounded-full border border-purple-100 outline-none" />
          </div>
          <button type="submit" className="w-full mt-8 py-4 bg-indigo-600 text-white rounded-full font-medium hover:bg-indigo-700 transition-all shadow-lg">{authMode === 'SIGNUP' ? 'Begin Journey' : 'Continue Journey'}</button>
          <button type="button" onClick={() => setAuthMode(authMode === 'SIGNUP' ? 'LOGIN' : 'SIGNUP')} className="w-full mt-6 text-indigo-400 text-sm hover:underline">
            {authMode === 'SIGNUP' ? 'Already have an account? Sign In' : "New here? Sign Up"}
          </button>
        </form>
      </div>
    );
  }

  if (view === 'VERIFY') {
    return (
      <div className="min-h-screen flex items-center justify-center serene-bg p-6 text-center">
        <div className="bg-white p-10 rounded-[2rem] shadow-xl w-full max-w-md border border-purple-50">
          <h2 className="text-3xl font-serif text-indigo-900 mb-4">Confirm Your Email</h2>
          <p className="text-gray-500 font-light mb-8">Verification code sent to {user?.email}. (Demo: 1111)</p>
          <input type="text" placeholder="0000" value={verifyCode} maxLength={4} onChange={e => setVerifyCode(e.target.value.replace(/[^0-9]/g, ''))} className="w-full mb-8 text-center text-4xl tracking-widest border-b-2 border-indigo-100 outline-none" />
          <button onClick={handleVerify} className="w-full py-4 bg-indigo-600 text-white rounded-full shadow-lg">Verify</button>
        </div>
      </div>
    );
  }

  if (view === 'DASHBOARD' && user) {
    return (
      <div className="min-h-screen serene-bg p-8">
        <div className="max-w-4xl mx-auto">
          <header className="flex justify-between items-end mb-12">
            <div>
              <p className="text-indigo-400 text-xs uppercase tracking-widest font-bold mb-1">Peace be with you</p>
              <h1 className="text-5xl font-serif text-indigo-900">{user.name}</h1>
            </div>
            <button onClick={() => { localStorage.removeItem('lumina_active_user_id'); setUser(null); setView('LANDING'); }} className="text-indigo-300 hover:text-indigo-600 uppercase tracking-widest text-[10px] font-bold border px-4 py-2 rounded-full">Sign Out</button>
          </header>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-4">
              <button onClick={() => startNewSession('free')} className="w-full bg-white p-8 rounded-[2.5rem] shadow-sm border border-purple-50 text-left hover:shadow-lg transition-all">
                <h3 className="text-2xl font-serif text-indigo-900 mb-1">2-Minute Reset</h3>
                <p className="text-gray-400 text-sm font-light">A brief moment of grounding and safety.</p>
              </button>
              <button onClick={() => startNewSession('paid')} className="w-full bg-indigo-600 p-8 rounded-[2.5rem] shadow-lg text-left text-white hover:bg-indigo-700 transition-all">
                <h3 className="text-2xl font-serif mb-1">Deep Journey</h3>
                <p className="text-indigo-100 text-sm font-light">Explore patterns, triggers, and protective roles.</p>
              </button>
            </div>
            <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-purple-50">
              <h3 className="text-xl font-serif text-indigo-900 mb-6 flex items-center">
                <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3" strokeWidth="2" strokeLinecap="round"/></svg>
                Previous Sessions
              </h3>
              <div className="space-y-3 overflow-y-auto max-h-[300px] pr-2 custom-scrollbar">
                {user.sessions.length > 0 ? user.sessions.map(s => (
                  <div key={s.id} onClick={() => { setActiveSession(s); setView('CHAT'); }} className="p-4 border rounded-2xl hover:bg-purple-50 transition-all cursor-pointer">
                    <div className="flex justify-between text-[10px] font-bold text-indigo-400 uppercase tracking-widest mb-1">
                      <span>{s.tier === 'free' ? 'Reset' : 'Journey'}</span>
                      <span>{new Date(s.lastUpdated).toLocaleDateString()}</span>
                    </div>
                    <p className="text-xs text-gray-400 italic line-clamp-1">"{s.messages[s.messages.length - 1]?.text}"</p>
                  </div>
                )) : <p className="text-xs text-gray-300 italic text-center py-8">Your journey history will appear here.</p>}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'CHAT' && activeSession) {
    return (
      <div className="flex flex-col h-screen serene-bg overflow-hidden">
        <div className="px-6 py-4 bg-white/80 border-b flex justify-between items-center">
          <button onClick={() => setView('DASHBOARD')} className="text-indigo-400 text-sm flex items-center">
            <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="2" strokeLinecap="round"/></svg>
            Dashboard
          </button>
          <div className="text-center">
            <h2 className="text-xl font-serif text-indigo-900">{activeSession.tier === 'free' ? 'Nervous System Reset' : 'Healing Space'}</h2>
            <div className="text-[9px] uppercase tracking-widest text-purple-300 font-bold">Session Active</div>
          </div>
          <button onClick={() => setView('REVIEW')} className="text-indigo-400 text-sm">Review</button>
        </div>
        <div ref={scrollRef} className="flex-1 overflow-y-auto px-4 md:px-12 py-8 space-y-4">
          <div className="max-w-4xl mx-auto">
            {activeSession.messages.map(msg => <MessageBubble key={msg.id} message={msg} />)}
            {isThinking && <div className="flex justify-start mb-6 message-fade-in"><div className="bg-white/80 text-gray-400 px-6 py-4 rounded-3xl rounded-tl-none italic text-sm">LuminaSoul is reflecting...</div></div>}
          </div>
        </div>
        <div className="p-4 md:p-8 bg-white/60 border-t">
          {activeSession.isComplete ? (
            <div className="max-w-4xl mx-auto text-center py-4">
              <p className="text-indigo-400 font-serif italic text-xl">"Awareness itself is healing."</p>
              <button onClick={() => setView('DASHBOARD')} className="mt-6 px-8 py-2 bg-indigo-500 text-white rounded-full shadow-md">Return Home</button>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto relative">
              <form onSubmit={handleSubmit}>
                <input type="text" value={inputValue} onChange={e => setInputValue(e.target.value)} placeholder={isThinking ? "Holding space..." : "Share what's in your heart..."} disabled={isThinking} className="w-full px-8 py-5 pr-20 bg-white border rounded-full shadow-lg outline-none" />
                <button type="submit" disabled={!inputValue.trim() || isThinking} className="absolute right-2 top-2 bottom-2 px-6 bg-indigo-600 text-white rounded-full shadow-md"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7l5 5m0 0l-5 5m5-5H6" strokeWidth="2" strokeLinecap="round"/></svg></button>
              </form>
            </div>
          )}
        </div>
      </div>
    );
  }

  if (view === 'REVIEW' && activeSession) {
    return (
      <div className="min-h-screen serene-bg p-8">
        <div className="max-w-4xl mx-auto">
          <header className="flex justify-between items-center mb-12">
            <h1 className="text-4xl font-serif text-indigo-900">Reflections</h1>
            <button onClick={() => setView('CHAT')} className="text-indigo-600 font-bold bg-white px-6 py-3 rounded-full shadow-sm">Back to Space</button>
          </header>
          <div className="space-y-6">
            {activeSession.messages.filter(m => m.role === 'user').map((m, idx) => (
              <div key={m.id} className="bg-white/70 p-8 rounded-[2rem] border relative group">
                <h4 className="text-purple-400 uppercase tracking-widest text-[10px] font-bold mb-2">Insight {idx + 1}</h4>
                <p className="text-xl text-indigo-900 italic font-light">"{m.text}"</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  }
  return null;
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { geminiService } from './services/geminiService';
import { GameStep, Message, User, UserSession, AppView, SessionTier } from './types';
import { STEP_ORDER } from './constants';
import ProgressBar from './components/ProgressBar';
import MessageBubble from './components/MessageBubble';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>('LANDING');
  const [user, setUser] = useState<User | null>(null);
  const [activeSession, setActiveSession] = useState<UserSession | null>(null);
  const [isThinking, setIsThinking] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [editingMessageId, setEditingMessageId] = useState<string | null>(null);

  // Auth States
  const [authMode, setAuthMode] = useState<'LOGIN' | 'SIGNUP'>('SIGNUP');
  const [formData, setFormData] = useState({ name: '', email: '', phone: '', password: '' });
  const [verifyCode, setVerifyCode] = useState('');
  const [authError, setAuthError] = useState('');

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const activeUserId = localStorage.getItem('lumina_active_user_id');
    if (activeUserId) {
      const savedUser = JSON.parse(localStorage.getItem(`user_${activeUserId}`) || 'null');
      if (savedUser && savedUser.isVerified) {
        setUser(savedUser);
        setView('DASHBOARD');
      }
    }
  }, []);

  useEffect(() => {
    if (user) {
      localStorage.setItem(`user_${user.email}`, JSON.stringify(user));
      if (user.isVerified) localStorage.setItem('lumina_active_user_id', user.email);
    }
  }, [user]);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [activeSession?.messages, isThinking]);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    if (authMode === 'SIGNUP') {
      if (!formData.name || !formData.email || !formData.phone || !formData.password) {
        setAuthError('Please fill in all fields.');
        return;
      }
      localStorage.setItem(`user_${formData.email}`, JSON.stringify({ ...formData, isVerified: false, sessions: [] }));
      setUser({ ...formData, isVerified: false, sessions: [] });
      setView('VERIFY');
    } else {
      const savedUser = JSON.parse(localStorage.getItem(`user_${formData.email}`) || 'null');
      if (savedUser && savedUser.password === formData.password) {
        setUser(savedUser);
        setView(savedUser.isVerified ? 'DASHBOARD' : 'VERIFY');
      } else {
        setAuthError('Incorrect details. Please try again.');
      }
    }
  };

  const handleVerify = (e: React.FormEvent) => {
    e.preventDefault();
    if (verifyCode === '1111') {
      if (user) {
        const verifiedUser = { ...user, isVerified: true };
        setUser(verifiedUser);
        setView('DASHBOARD');
      }
    } else {
      setAuthError('Code is 1111 for this demo.');
    }
  };

  const startNewSession = async (tier: SessionTier) => {
    const newSession: UserSession = {
      id: Math.random().toString(36).substring(7),
      messages: [],
      currentStep: GameStep.START,
      lastUpdated: new Date(),
      isComplete: false,
      tier
    };
    setActiveSession(newSession);
    setView('CHAT');
    setIsThinking(true);
    geminiService.initChat();

    const tierContext = tier === 'free' 
      ? "I am starting a 2-MINUTE NERVOUS SYSTEM RESET. Keep it very brief." 
      : "I am starting a DEEP JOURNEY. We will move through multiple layers of awareness.";

    const response = await geminiService.sendMessage(
      `I am ${user?.name}. ${tierContext} (SYSTEM: MANDATORY — Before you start, you MUST perform the full LuminaSoul Grounding Breath ritual (Setup, 3-2-7-1 Technique, Repetitions, and Affirmations) as defined in your instructions. Do not skip any part of the grounding sequence.)`
    );

    const modelMsg: Message = { id: 'm1', role: 'model', text: response, timestamp: new Date(), isQuestion: true };
    const updatedSession = { ...newSession, messages: [modelMsg] };
    setActiveSession(updatedSession);
    setIsThinking(false);
    updateUserSessions(updatedSession);
  };

  const updateUserSessions = (session: UserSession) => {
    if (!user) return;
    const otherSessions = user.sessions.filter(s => s.id !== session.id);
    setUser({ ...user, sessions: [session, ...otherSessions] });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputValue.trim() || isThinking || !activeSession) return;

    const text = inputValue;
    setInputValue('');
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text, timestamp: new Date() };
    const messagesWithUser = [...activeSession.messages, userMsg];
    setActiveSession({ ...activeSession, messages: messagesWithUser });
    setIsThinking(true);

    let nextStep = activeSession.currentStep;
    const idx = STEP_ORDER.indexOf(activeSession.currentStep) + 1;
    nextStep = STEP_ORDER[idx] || GameStep.END;

    if (activeSession.tier === 'free' && activeSession.messages.length >= 3) {
      nextStep = GameStep.END;
    }

    const prompt = `${text} (SYSTEM: MANDATORY — Acknowledge warmly. Then, BEFORE asking the next question, you MUST perform the full LuminaSoul Grounding Breath ritual (3-2-7-1 Technique) and both affirmations: "My body is listening. I am allowed to slow down" and "I am here. I am supported. I am safe enough in this moment." This ritual is required at every pause.)`;

    const response = await geminiService.sendMessage(prompt);
    const modelMsg: Message = { id: (Date.now() + 1).toString(), role: 'model', text: response, timestamp: new Date(), isQuestion: true };

    const finalSession = { 
      ...activeSession, 
      messages: [...messagesWithUser, modelMsg],
      currentStep: nextStep,
      isComplete: nextStep === GameStep.END,
      lastUpdated: new Date()
    };
    setActiveSession(finalSession);
    setIsThinking(false);
    updateUserSessions(finalSession);
  };

  if (view === 'LANDING') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center p-6 serene-bg text-center">
        <div className="max-w-2xl bg-white/40 backdrop-blur-lg p-12 rounded-[3rem] shadow-2xl border border-white/50">
          <h1 className="text-6xl text-indigo-900 mb-6 font-serif tracking-tight">LuminaSoul</h1>
          <p className="text-xl text-indigo-700/80 mb-12 font-light italic">"A sacred space for your nervous system to be heard."</p>
          <button onClick={() => setView('AUTH')} className="px-12 py-4 bg-indigo-600 text-white rounded-full text-lg shadow-xl hover:bg-indigo-700 transition-all font-medium">
            Enter the Space
          </button>
        </div>
      </div>
    );
  }

  if (view === 'AUTH') {
    return (
      <div className="min-h-screen flex items-center justify-center serene-bg p-6">
        <form onSubmit={handleAuth} className="bg-white p-10 rounded-[2rem] shadow-xl w-full max-w-md border border-purple-50">
          <h2 className="text-3xl font-serif text-indigo-900 mb-2 text-center">{authMode === 'SIGNUP' ? 'Join LuminaSoul' : 'Welcome Back'}</h2>
          <p className="text-gray-400 text-sm mb-8 text-center font-light">{authMode === 'SIGNUP' ? 'Create a space for your inner peace.' : 'Reconnect with your journey.'}</p>
          {authError && <div className="mb-6 p-4 bg-red-50 text-red-500 text-xs rounded-2xl border border-red-100">{authError}</div>}
          <div className="space-y-4">
            {authMode === 'SIGNUP' && (
              <>
                <input type="text" placeholder="Full Name" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full px-6 py-4 rounded-full border border-purple-100 outline-none focus:ring-2 focus:ring-indigo-100 transition-all" />
                <input type="tel" placeholder="Phone Number" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} className="w-full px-6 py-4 rounded-full border border-purple-100 outline-none focus:ring-2 focus:ring-indigo-100 transition-all" />
              </>
            )}
            <input type="email" placeholder="Email Address" value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} className="w-full px-6 py-4 rounded-full border border-purple-100 outline-none focus:ring-2 focus:ring-indigo-100 transition-all" />
            <input type="password" placeholder="Password" value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} className="w-full px-8 py-4 rounded-full border border-purple-100 outline-none focus:ring-2 focus:ring-indigo-100 transition-all" />
          </div>
          <button type="submit" className="w-full mt-8 py-4 bg-indigo-600 text-white rounded-full font-medium hover:bg-indigo-700 transition-all shadow-lg active:scale-95 transition-transform">{authMode === 'SIGNUP' ? 'Begin Journey' : 'Continue Journey'}</button>
          <button type="button" onClick={() => setAuthMode(authMode === 'SIGNUP' ? 'LOGIN' : 'SIGNUP')} className="w-full mt-6 text-indigo-400 text-sm hover:underline">
            {authMode === 'SIGNUP' ? 'Already have an account? Sign In' : "New here? Sign Up"}
          </button>
        </form>
      </div>
    );
  }

  if (view === 'VERIFY') {
    return (
      <div className="min-h-screen flex items-center justify-center serene-bg p-6 text-center">
        <div className="bg-white p-10 rounded-[2rem] shadow-xl w-full max-w-md border border-purple-50">
          <h2 className="text-3xl font-serif text-indigo-900 mb-4 tracking-tight">Confirm Your Email</h2>
          <p className="text-gray-500 font-light mb-8">Verification code sent to {user?.email}. (Demo: 1111)</p>
          <input type="text" placeholder="0000" value={verifyCode} maxLength={4} onChange={e => setVerifyCode(e.target.value.replace(/[^0-9]/g, ''))} className="w-full mb-8 text-center text-4xl tracking-[0.3em] font-serif border-b-2 border-indigo-100 outline-none focus:border-indigo-400 transition-all" />
          <button onClick={handleVerify} className="w-full py-4 bg-indigo-600 text-white rounded-full shadow-lg font-medium hover:bg-indigo-700 transition-all">Verify</button>
        </div>
      </div>
    );
  }

  if (view === 'DASHBOARD' && user) {
    return (
      <div className="min-h-screen serene-bg p-8">
        <div className="max-w-4xl mx-auto">
          <header className="flex justify-between items-end mb-12">
            <div>
              <p className="text-indigo-400 text-xs uppercase tracking-[0.3em] font-bold mb-1">Peace be with you</p>
              <h1 className="text-5xl font-serif text-indigo-900">{user.name}</h1>
            </div>
            <button onClick={() => { localStorage.removeItem('lumina_active_user_id'); setUser(null); setView('LANDING'); }} className="text-indigo-300 hover:text-indigo-600 uppercase tracking-widest text-[10px] font-bold border px-6 py-2 rounded-full transition-all">Sign Out</button>
          </header>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-6">
              <button onClick={() => startNewSession('free')} className="w-full bg-white p-8 rounded-[2.5rem] shadow-sm border border-purple-50 text-left hover:shadow-xl transition-all group">
                <h3 className="text-2xl font-serif text-indigo-900 mb-2 group-hover:text-indigo-600 transition-colors">2-Minute Reset</h3>
                <p className="text-gray-400 text-sm font-light leading-relaxed">A brief moment of grounding, safety, and focused regulation breath.</p>
              </button>
              <button onClick={() => startNewSession('paid')} className="w-full bg-indigo-600 p-8 rounded-[2.5rem] shadow-lg text-left text-white hover:bg-indigo-700 transition-all relative overflow-hidden group">
                <div className="absolute top-0 right-0 w-24 h-24 bg-white/10 rounded-bl-full -mr-10 -mt-10 transition-transform group-hover:scale-125"></div>
                <h3 className="text-2xl font-serif mb-2">Deep Journey</h3>
                <p className="text-indigo-100 text-sm font-light leading-relaxed">Explore patterns, triggers, and protective roles in a sacred flowing session.</p>
              </button>
            </div>
            <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-purple-50 flex flex-col">
              <h3 className="text-xl font-serif text-indigo-900 mb-6 flex items-center">
                <svg className="w-5 h-5 mr-3 text-purple-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" strokeWidth="2" strokeLinecap="round"/></svg>
                Previous Sessions
              </h3>
              <div className="space-y-4 overflow-y-auto max-h-[340px] pr-2 custom-scrollbar flex-1">
                {user.sessions.length > 0 ? user.sessions.map(s => (
                  <div key={s.id} onClick={() => { setActiveSession(s); setView('CHAT'); }} className="p-5 border border-purple-50 rounded-2xl hover:bg-purple-50 transition-all cursor-pointer group">
                    <div className="flex justify-between text-[10px] font-bold text-indigo-400 uppercase tracking-[0.2em] mb-2">
                      <span>{s.tier === 'free' ? 'Reset' : 'Journey'}</span>
                      <span>{new Date(s.lastUpdated).toLocaleDateString()}</span>
                    </div>
                    <p className="text-xs text-gray-500 italic line-clamp-1 group-hover:text-indigo-600 transition-colors">"{s.messages[s.messages.length - 1]?.text}"</p>
                  </div>
                )) : <div className="text-center py-12 text-gray-300 italic text-sm">Your healing history will appear here.</div>}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  if (view === 'CHAT' && activeSession) {
    return (
      <div className="flex flex-col h-screen serene-bg overflow-hidden">
        <div className="px-6 py-4 bg-white/90 border-b border-purple-50 flex justify-between items-center z-10">
          <button onClick={() => setView('DASHBOARD')} className="text-indigo-400 text-sm flex items-center hover:text-indigo-700 transition-colors">
            <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="2" strokeLinecap="round"/></svg>
            Dashboard
          </button>
          <div className="text-center">
            <h2 className="text-xl font-serif text-indigo-900 tracking-tight">{activeSession.tier === 'free' ? 'Nervous System Reset' : 'Healing Space'}</h2>
            <div className="text-[9px] uppercase tracking-[0.3em] text-indigo-300 font-bold">Session Active</div>
          </div>
          <button onClick={() => setView('REVIEW')} className="text-indigo-400 text-sm hover:text-indigo-700 transition-colors">Reflections</button>
        </div>
        <div ref={scrollRef} className="flex-1 overflow-y-auto px-4 md:px-12 py-8 space-y-4 custom-scrollbar">
          <div className="max-w-4xl mx-auto">
            {activeSession.messages.map(msg => <MessageBubble key={msg.id} message={msg} />)}
            {isThinking && (
              <div className="flex justify-start mb-6 message-fade-in">
                <div className="bg-white/80 text-gray-400 px-8 py-5 rounded-3xl rounded-tl-none italic text-sm border border-purple-50 shadow-sm">
                  LuminaSoul is holding space...
                </div>
              </div>
            )}
          </div>
        </div>
        <div className="p-4 md:p-8 bg-white/70 backdrop-blur-md border-t border-purple-50 shadow-2xl">
          {activeSession.isComplete ? (
            <div className="max-w-4xl mx-auto text-center py-6">
              <p className="text-indigo-500 font-serif italic text-2xl mb-8">"Awareness itself is healing."</p>
              <button onClick={() => setView('DASHBOARD')} className="px-12 py-3 bg-indigo-600 text-white rounded-full shadow-lg hover:bg-indigo-700 transition-all font-medium">Return to Dashboard</button>
            </div>
          ) : (
            <div className="max-w-4xl mx-auto relative">
              <form onSubmit={handleSubmit}>
                <input 
                  type="text" 
                  value={inputValue} 
                  onChange={e => setInputValue(e.target.value)} 
                  placeholder={isThinking ? "Quiet moments..." : "Share what's in your heart..."} 
                  disabled={isThinking} 
                  className="w-full px-10 py-6 pr-24 bg-white border border-indigo-100 rounded-full shadow-lg outline-none focus:ring-2 focus:ring-indigo-100 transition-all text-lg font-light" 
                />
                <button 
                  type="submit" 
                  disabled={!inputValue.trim() || isThinking} 
                  className="absolute right-3 top-3 bottom-3 px-8 bg-indigo-600 text-white rounded-full shadow-md hover:bg-indigo-700 disabled:bg-gray-200 transition-all"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7l5 5m0 0l-5 5m5-5H6" strokeWidth="2" strokeLinecap="round"/></svg>
                </button>
              </form>
            </div>
          )}
        </div>
      </div>
    );
  }

  if (view === 'REVIEW' && activeSession) {
    return (
      <div className="min-h-screen serene-bg p-8">
        <div className="max-w-4xl mx-auto">
          <header className="flex justify-between items-center mb-12">
            <h1 className="text-4xl font-serif text-indigo-900 tracking-tight">Reflections</h1>
            <button onClick={() => setView('CHAT')} className="text-indigo-600 font-bold bg-white px-8 py-3 rounded-full shadow-sm hover:shadow-md transition-all">Back to Session</button>
          </header>
          <div className="space-y-8 pb-12">
            {activeSession.messages.filter(m => m.role === 'user').map((m, idx) => (
              <div key={m.id} className="bg-white/80 p-10 rounded-[2.5rem] border border-indigo-50 shadow-sm relative group overflow-hidden">
                <div className="absolute top-0 left-0 w-2 h-full bg-indigo-200"></div>
                <h4 className="text-indigo-300 uppercase tracking-[0.3em] text-[10px] font-bold mb-4">Discovery {idx + 1}</h4>
                <p className="text-2xl text-indigo-900 italic font-light leading-relaxed">"{m.text}"</p>
              </div>
            ))}
            {activeSession.messages.filter(m => m.role === 'user').length === 0 && (
              <div className="text-center py-24 text-gray-400 italic">No reflections have been shared in this session yet.</div>
            )}
          </div>
        </div>
      </div>
    );
  }
  return null;
};

export default App;
